class GetNotificationsByType {
  GetNotificationsByType({
      this.isSuccess, 
      this.message, 
      this.data,});

  GetNotificationsByType.fromJson(dynamic json) {
    isSuccess = json['isSuccess'];
    message = json['message'];
    if (json['data'] != null) {
      data = [];
      json['data'].forEach((v) {
        data?.add(Data.fromJson(v));
      });
    }
  }
  bool? isSuccess;
  String? message;
  List<Data>? data;
GetNotificationsByType copyWith({  bool? isSuccess,
  String? message,
  List<Data>? data,
}) => GetNotificationsByType(  isSuccess: isSuccess ?? this.isSuccess,
  message: message ?? this.message,
  data: data ?? this.data,
);
  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['isSuccess'] = isSuccess;
    map['message'] = message;
    if (data != null) {
      map['data'] = data?.map((v) => v.toJson()).toList();
    }
    return map;
  }

}

